import { useEffect, useState } from "react";
import axios from "axios";

/* MODAL COMPONENT */
function Modal({ submitResolve, setProofImage, close }) {
  return (
    <div style={{
      position: "fixed",
      top: 0, left: 0,
      width: "100%", height: "100%",
      background: "rgba(0,0,0,0.7)",
      display: "flex",
      justifyContent: "center",
      alignItems: "center"
    }}>
      <div style={{
        background: "#142c4c",
        padding: 30,
        borderRadius: 10
      }}>
        <h3>Upload Proof</h3>

        <input
          type="file"
          accept="image/*"
          capture="environment"
          onChange={(e) => setProofImage(e.target.files[0])}
        />

        <br /><br />

        <button onClick={submitResolve}>Submit</button>
        <button onClick={close} style={{ marginLeft: 10 }}>Cancel</button>
      </div>
    </div>
  );
}

export default function AdminDashboard() {

  const [alerts, setAlerts] = useState([]);
  const [loading, setLoading] = useState(true);

  const [showModal, setShowModal] = useState(false);
  const [selectedAlertId, setSelectedAlertId] = useState(null);
  const [proofImage, setProofImage] = useState(null);

  /* LOAD ALERTS */
  const loadAlerts = () => {
    axios.get("http://127.0.0.1:8000/api/admin-alerts/")
      .then(res => {
        setAlerts(res.data);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  };

  useEffect(() => {
    loadAlerts();
  }, []);

  /* OPEN MODAL */
  const openResolveModal = (id) => {
    setSelectedAlertId(id);
    setShowModal(true);
  };

  /* SUBMIT RESOLVE */
  const submitResolve = () => {

    if (!proofImage) {
      alert("Upload proof first");
      return;
    }

    navigator.geolocation.getCurrentPosition((pos) => {

      const formData = new FormData();
      formData.append("proof_image", proofImage);
      formData.append("latitude", pos.coords.latitude);
      formData.append("longitude", pos.coords.longitude);

      axios.post(
        `http://127.0.0.1:8000/api/resolve-api/${selectedAlertId}/`,
        formData
      )
        .then(() => {
          alert("Resolved ✅");
          setShowModal(false);
          setProofImage(null);
          loadAlerts();
        })
        .catch(() => alert("Verification failed ❌"));

    });
  };

  if (loading) return <h2>Loading...</h2>;

  return (
    <div style={{ padding: 30 }}>

      <h1>Admin Dashboard</h1>

      {alerts.map(a => (
        <div key={a.id} style={{
          background: "#eee",
          margin: 10,
          padding: 10
        }}>
          <p>{a.message}</p>
          <p>Status: {a.status}</p>

          {a.status !== "resolved" && (
            <button onClick={() => openResolveModal(a.id)}>
              Resolve
            </button>
          )}
        </div>
      ))}

      {showModal && (
        <Modal
          submitResolve={submitResolve}
          setProofImage={setProofImage}
          close={() => setShowModal(false)}
        />
      )}

    </div>
  );
}
